SELECT users.name AS user_name, angels.name AS angel_name, angels.quality AS heavenly_virtue
FROM users
INNER JOIN angels ON users.angel_id = angels.angel_id;

SELECT name
FROM angels
WHERE angel_id = 1;

SELECT DISTINCT administrators.name
FROM administrators
JOIN prayers ON administrators.admin_id = prayers.created_by;

SELECT name 
FROM users 
WHERE angel_id = (SELECT angel_id FROM angels WHERE name = 'Jeliel');
